  ('diplomatic-5118c8cd-moex-00369', 'diplomatic-5118c8cd', 'diplomatic-5118c8cd-moex-110-c655adf3', 'sub-diplomatic-5118c8cd-05', NULL, 'single_choice', '行為學派是近年研究比較政府與政治的重要途徑。下列何者非屬其主張內容？', '["人是制度建立基礎", "強調通則化的研究途徑", "制度架構會影響競爭結果", "制度是政治行為者進行競爭的架構"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:08+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-泰文組"}'::jsonb, NULL),
  ('diplomatic-5118c8cd-moex-00370', 'diplomatic-5118c8cd', 'diplomatic-5118c8cd-moex-110-c655adf3', 'sub-diplomatic-5118c8cd-05', NULL, 'single_choice', '下列何者非屬比較政治研究範圍中，憲政主義的主張？', '["應對抗開明專制思潮", "主政者行使權力須受憲法規範", "強調法治取代人治，行政部門依法可儘量擴展權限", "公權力運作應符合正當法律程序"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:08+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-泰文組"}'::jsonb, NULL),
  ('diplomatic-5118c8cd-moex-00371', 'diplomatic-5118c8cd', 'diplomatic-5118c8cd-moex-110-c655adf3', 'sub-diplomatic-5118c8cd-05', NULL, 'single_choice', '下列對政治制度內涵的敘述，何者錯誤？', '["是敵對政治勢力間的妥協產物", "施行重點在於規範行政、立法與司法部門的關係", "各國基本上包括內閣制、總統制和半總統制等3種類型", "意識型態對政治勢力有決定性的影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:08+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-泰文組"}'::jsonb, NULL),
  ('diplomatic-5118c8cd-moex-00372', 'diplomatic-5118c8cd', 'diplomatic-5118c8cd-moex-110-c655adf3', 'sub-diplomatic-5118c8cd-05', NULL, 'single_choice', '下列何者非屬各國辦理公民投票的考量範圍？', '["公投結果是否能超過半數門檻", "對政黨制度的干預或影響", "尋求直接民意與間接民意之合致", "國會的支持與反對意見"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:08+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-泰文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00001', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-13504c0c', 'sub-diplomatic-535efab1-01', NULL, 'single_choice', '下列情境語句，何者用法最為恰當？', '["新居落成：「屋上建瓴，恭喜新居落成。」", "活動開幕：「感謝各位的蒞臨，讓這次的展覽可以厚往薄來。」", "榮退餐會：「恭喜您可以自在逍遙，從今以後可以快意恩仇了。」", "婚禮祝賀：「在這兩家合婚的大好日子，要祝福新人喜結良緣、花好月圓。」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:32+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00002', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-13504c0c', 'sub-diplomatic-535efab1-01', NULL, 'single_choice', '「不要忘記生命才是創作中最重要的一環。在我們對戲劇理論抱持激情的時候，記 得要先對生命抱持激情。對生命敏感，對人好奇，對現行的世界保有批判的態度， 同時擁有廣納包容的胸襟。」 下列敘述，何者最貼近本文意旨？', '["人要正向思考，不能輕言放棄生命", "好的編劇不僅熟知理論，也對生活周遭充滿關注與熱情", "為人當有雅量，不該對別人好奇，凡事包容體諒即是尊重", "教師教導戲劇理論時不能僅照本宣科，也應教學生認真生活"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:32+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00003', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-13504c0c', 'sub-diplomatic-535efab1-01', NULL, 'single_choice', '「歷史從來都有些勢利眼。歷史的一切總要透過『層積堆疊』，經過『集體記憶』的 萃取純化，方才得以逐漸定型。然而，在此『歷史造山運動』過程之中，歷史的光 圈很容易只集中在『歷史時刻』，相對地，『時刻之前』的脈絡面貌，卻常常會被有 意無意地遺忘或改變了。」 最適合用來說明上文的是：', '["人類歷史經過漫長時間累積，是給後世的智慧結晶", "過往的歷史充滿許多偏見，編修史書尤須格外謹慎", "閱讀歷史如果僅集中特定時刻，容易忽略前後脈絡", "歷史是屬於不同族群的集體記憶，應注意地方差異"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:32+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00004', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-13504c0c', 'sub-diplomatic-535efab1-01', NULL, 'single_choice', '「別忘了這是個國際化的時代。到哪裡都看得到同樣的連鎖速食店、同樣的二十四 小時便利商店、同樣的好萊塢電影海報。完全陌生的角落正逐漸從這個世界上消失。 在這樣的時代我們怎麼可能還有完全的流浪？像馬可波羅、哥倫布那樣，踏上一塊 完全沒有線索可循的土地，連送信回家的信差都沒有，在我們這個時代已經越來越 像則神話。在這個所有角落越來越像的世界裡，怎麼可能還有完全的流浪？」 下列說明，最切近上文主旨的是：', '["人們渴望流浪的感覺", "最好的旅行是如同探險家一般地發現新世界", "世界趨向高度同質化，因此人們認識在地就等於認識了全世界", "全球化之下，各地過多的文化複製空間所帶來的熟悉感，將影響人們的旅行經驗"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:32+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00005', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-13504c0c', 'sub-diplomatic-535efab1-01', NULL, 'single_choice', '「攝影者開始發現自然界的詩意後便停不下來，畢竟捕捉動物一瞬間運動狀態的不 只是機械，還是心靈。美的喚醒如此獨特，以至於同樣一台機械交給不同的人將獲 致不同的結果，而同樣一張照片帶給觀看者的情緒震動，也絕對不是那些一開始希 望相機為科學理性服務的人所能理解的。」 下列選項，何者最不符合上文旨意？', '["相機產生有意義的畫面，是因攝影者使用的機械不同", "照片凝止自然界的運動，使觀看者更能體會自然之美", "照片讓觀看者情緒震動，因相機能捕捉動物瞬間樣態", "影像在藝術與科學間飛翔，透過心靈喚醒自然界之美"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:32+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL)
